import React, { useState, useEffect } from 'react';
import { getChannels } from '../services/api';
import { Link } from 'react-router-dom';

const RADIO_CATEGORIES = ['radio', 'music', 'música'];
const isRadio = (cat) => RADIO_CATEGORIES.some(r => cat?.toLowerCase().includes(r));

const Channels = () => {
  const [channels, setChannels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('Todos');

  useEffect(() => {
    getChannels({}).then(data => {
      // Solo canales de TV, sin radio
      setChannels(data.filter(c => !isRadio(c.category)));
    }).catch(console.error).finally(() => setLoading(false));
  }, []);

  const categories = ['Todos', ...new Set(channels.map(c => c.category).filter(Boolean))];

  const filtered = channels.filter(c => {
    const matchSearch = c.name.toLowerCase().includes(search.toLowerCase());
    const matchCat = activeCategory === 'Todos' || c.category === activeCategory;
    return matchSearch && matchCat;
  });

  if (loading) return (
    <div className="flex justify-center items-center h-[70vh]">
      <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-red-600"></div>
    </div>
  );

  return (
    <div className="pb-10">
      {/* Hero */}
      <div className="bg-gradient-to-b from-gray-800 to-gray-900 px-6 py-10 mb-6 text-center">
        <h1 className="text-4xl font-bold mb-2">📺 TV en Vivo</h1>
        <p className="text-gray-400 mb-6">Canales de televisión en directo</p>
        <input
          type="text"
          placeholder="Buscar canal..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full max-w-md px-4 py-3 bg-gray-700 rounded-full border border-gray-600 focus:outline-none focus:border-red-600 text-white"
        />
      </div>

      {/* Categorías */}
      <div className="flex gap-2 px-6 mb-6 overflow-x-auto pb-2">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
              activeCategory === cat ? 'bg-red-600 text-white' : 'bg-gray-700 hover:bg-gray-600 text-gray-300'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Grid */}
      <div className="px-6">
        {filtered.length > 0 ? (
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
            {filtered.map(channel => (
              <Link
                key={channel.id}
                to={`/player/channel/${channel.id}`}
                className="bg-gray-800 hover:bg-gray-700 rounded-xl p-4 flex flex-col items-center gap-3 transition-all hover:scale-105 hover:ring-2 hover:ring-red-600"
              >
                {channel.logo ? (
                  <img src={channel.logo} alt={channel.name} className="w-16 h-16 object-contain bg-white rounded-lg p-1" onError={(e) => e.target.style.display = 'none'} />
                ) : (
                  <div className="w-16 h-16 bg-gray-600 rounded-lg flex items-center justify-center text-2xl">📺</div>
                )}
                <span className="text-sm font-medium text-center truncate w-full">{channel.name}</span>
                <span className="text-xs text-gray-400 bg-gray-700 px-2 py-0.5 rounded-full truncate w-full text-center">{channel.category}</span>
              </Link>
            ))}
          </div>
        ) : (
          <div className="text-center py-16 text-gray-400">
            <p className="text-xl">No hay canales disponibles</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Channels;
